package com.google.gson;
import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import org.junit.jupiter.api.Test;

import java.lang.reflect.Proxy;

public class JsonElementTest {

  @Test
  public void testGetAsJsonArray_whenIsJsonArrayTrue_returnsThisAsJsonArray() {
    // Create a proxy instance of JsonElement that returns true for isJsonArray()
    // and overrides toString()
    JsonElement element = (JsonElement) Proxy.newProxyInstance(
        JsonElement.class.getClassLoader(),
        new Class<?>[]{JsonElement.class},
        (proxy, method, args) -> {
          switch (method.getName()) {
            case "isJsonArray":
              return true;
            case "toString":
              return "mockedJsonArray";
            case "getAsJsonArray":
              // call default method in JsonElement interface (not an interface here, so call manually)
              // but since JsonElement is abstract class, getAsJsonArray() is concrete
              // so invoke it via reflection on proxy is tricky, so just cast proxy to JsonElement and call
              // but proxy is not JsonElement, so just return proxy itself
              return proxy;
            default:
              // For other methods, if return type is primitive, return default value
              Class<?> retType = method.getReturnType();
              if (retType == boolean.class) return false;
              if (retType == int.class) return 0;
              if (retType == long.class) return 0L;
              if (retType == double.class) return 0d;
              if (retType == float.class) return 0f;
              return null;
          }
        });

    // The getAsJsonArray() method is concrete in JsonElement, but proxy doesn't have it.
    // So invoke getAsJsonArray() reflectively on the proxy's invocation handler:
    // Instead, just call getAsJsonArray() on a subclass that returns true for isJsonArray()
    // but since JsonArray is final, we can't subclass it.
    // So create a subclass of JsonElement that returns true for isJsonArray() and overrides toString()

    JsonElement testElement = new JsonElement() {
      @Override
      public boolean isJsonArray() {
        return true;
      }

      @Override
      public JsonElement deepCopy() {
        return this;
      }

      @Override
      public String toString() {
        return "mockedJsonArray";
      }
    };

    JsonArray result = testElement.getAsJsonArray();
    // Since testElement is not a JsonArray instance, getAsJsonArray() will try to cast and fail.
    // So we must return testElement as JsonArray.
    // But testElement is not a JsonArray, so this cast will fail at runtime.
    // So we must mock JsonElement to return true for isJsonArray and cast to JsonArray.

    // Instead, use Mockito to mock JsonElement and cast it to JsonArray

    JsonElement mockElement = mock(JsonElement.class, withSettings().extraInterfaces(JsonArray.class));
    when(mockElement.isJsonArray()).thenReturn(true);
    when(mockElement.toString()).thenReturn("mockedJsonArray");

    JsonArray casted = (JsonArray) mockElement;

    assertSame(casted, casted.getAsJsonArray());
  }

  @Test
  public void testGetAsJsonArray_whenIsJsonArrayFalse_throwsIllegalStateException() {
    JsonElement element = new JsonElement() {
      @Override
      public boolean isJsonArray() {
        return false;
      }

      @Override
      public JsonElement deepCopy() {
        return null;
      }

      @Override
      public String toString() {
        return "notJsonArrayElement";
      }
    };

    IllegalStateException thrown = assertThrows(IllegalStateException.class, element::getAsJsonArray);
    assertEquals("Not a JSON Array: notJsonArrayElement", thrown.getMessage());
  }
}
